        let v = edge[1]
        let w = edge[2]
        adj[u].push([v, w, 0])  # 0 indicates normal edge
        reverse_adj[v].push([u, w, 1])  # 1 indicates it's a potential reversed edge
    }

    # Dijkstra's setup
    let dist = Array<Array<Int64>>(num_nodes, [Int64.max, Int64.max])
    dist[0] = [0, Int64.max]

    let heap = PriorityQueue<Array<Int64>>(compare: (a, b) => a[2] < b[2])
    heap.push([0, 0, 0])  # [node, used_switch, current_cost]

    while not heap.empty() {
        let current = heap.pop()
        let u = current[0]
        let used = current[1]
        let cost = current[2]

        if u == num_nodes - 1 {
            return cost
        }

        if cost > dist[u][used] {
            continue
        }

        # Process normal edges
        for edge in adj[u] {
            let v = edge[0]
            let w = edge[1]
            let new_cost = cost + w
            if new_cost < dist[v][used] {
                dist[v][used] = new_cost
                heap.push([v, used, new_cost])
            }
        }

        # Process potential reversed edges (if switch not used yet)
        if used == 0 {
            for edge in reverse_adj[u] {
                let v = edge[0]  # original source
                let w = edge[1]
                let new_cost = cost + 2 * w
                if new_cost < dist[v][1] {
                    dist[v][1] = new_cost
                    heap.push([v, 1, new_cost])
                }
            }
        }
    }

    let result = min(dist[num_nodes - 1][0], dist[num_nodes - 1][1])
    return result == Int64.max ? -1 : result
