    // Build the adjacency list
    adj := make(Array<Array<Array<Int64>>>, n)
    for i := 0; i < n; i++ {
        adj[i] = make(Array<Array<Int64>>, 0)
    }
    for edge in edges {
        u := edge[0]
        v := edge[1]
        w := edge[2]
        adj[u].append([v, w, 0])  // 0 indicates normal edge
    }

    // Initialize distance array
    dist := make(Array<Array<Int64>>, n)
    for i := 0; i < n; i++ {
        dist[i] = [INF, INF]
    }
    dist[0][0] = 0  // [0][0]: not used switch, [0][1]: used switch

    // Priority queue: (distance, node, switch_used)
    pq := make(Heap<Array<Int64>>, 0)
    heap.push(pq, [0, 0, 0])

    while len(pq) > 0 {
        current := heap.pop(pq)
        d := current[0]
        u := current[1]
        used := current[2]

        if u == n - 1 {
            return d
        }

        if d > dist[u][used] {
            continue
        }

        for edge in adj[u] {
            v := edge[0]
            w := edge[1]
            // Normal traversal
            if dist[v][used] > d + w {
                dist[v][used] = d + w
                heap.push(pq, [dist[v][used], v, used])
            }
            // If switch not used, try to reverse an incoming edge
            if used == 0 {
                for in_edge in adj[v] {
                    if in_edge[0] == u {
                        reversed_w := in_edge[1]
                        if dist[v][1] > d + 2 * reversed_w {
                            dist[v][1] = d + 2 * reversed_w
                            heap.push(pq, [dist[v][1], v, 1])
                        }
                    }
                }
            }
        }
    }

    result := min(dist[n - 1][0], dist[n - 1][1])
    if result == INF {
        return -1
    } else {
        return result
