import Foundation

func solve(n: Int64, edges: Array<Array<Int64>>) -> Int64 {
    let nInt = Int(n)
    var adj = [[(v: Int, w: Int)]](repeating: [], count: nInt)
    var reverseAdj = [[(v: Int, w: Int)]](repeating: [], count: nInt)

    for edge in edges {
        let u = Int(edge[0])
        let v = Int(edge[1])
        let w = Int(edge[2])
        adj[u].append((v: v, w: w))
        reverseAdj[v].append((v: u, w: w))
    }

    var dist = [[Int]](repeating: [Int.max, Int.max], count: nInt)
    dist[0][0] = 0
    dist[0][1] = 0

    var heap = Heap<(node: Int, used: Int, cost: Int)> { $0.cost < $1.cost }
    heap.insert((node: 0, used: 0, cost: 0))
    heap.insert((node: 0, used: 1, cost: 0))

    while !heap.isEmpty {
        let current = heap.remove()!
        let u = current.node
        let used = current.used
        let cost = current.cost

        if u == nInt - 1 {
            return Int64(cost)
        }

        if cost > dist[u][used] {
            continue
        }

        for edge in adj[u] {
            let v = edge.v
            let w = edge.w
            let newCost = cost + w
            if newCost < dist[v][used] {
                dist[v][used] = newCost
                heap.insert((node: v, used: used, cost: newCost))
            }
        }

        if used == 0 {
            for edge in reverseAdj[u] {
                let v = edge.v
                let w = edge.w
                let newCost = cost + 2 * w
                if newCost < dist[v][1] {
                    dist[v][1] = newCost
                    heap.insert((node: v, used: 1, cost: newCost))
                }
            }
        }
    }

    return -1
}

struct Heap<T> {
    private var elements: [T]
    private let priorityFunction: (T, T) -> Bool

    var isEmpty: Bool {
        return elements.isEmpty
    }

    init(sort: @escaping (T, T) -> Bool) {
        self.elements = []
        self.priorityFunction = sort
    }

    mutating func insert(_ value: T) {
        elements.append(value)
        siftUp(from: elements.count - 1)
    }

    mutating func remove() -> T? {
        guard !elements.isEmpty else { return nil }
        if elements.count == 1 {
            return elements.removeLast()
        } else {
            let value = elements[0]
            elements[0] = elements.removeLast()
            siftDown(from: 0)
            return value
        }
    }

    private mutating func siftUp(from index: Int) {
        var child = index
        var parent = parentIndex(of: child)
        while child > 0 && priorityFunction(elements[child], elements[parent]) {
            elements.swapAt(child, parent)
            child = parent
            parent = parentIndex(of: child)
        }
    }

    private mutating func siftDown(from index: Int) {
        let left = leftChildIndex(of: index)
        let right = rightChildIndex(of: index)
        var first = index
        if left < elements.count && priorityFunction(elements[left], elements[first]) {
            first = left
        }
        if right < elements.count && priorityFunction(elements[right], elements[first]) {
            first = right
        }
        if first == index { return }
        elements.swapAt(index, first)
        siftDown(from: first)
    }

    private func parentIndex(of index: Int) -> Int {
        return (index - 1) / 2
    }

    private func leftChildIndex(of index: Int) -> Int {
        return 2 * index + 1
    }

    private func rightChildIndex(of index: Int) -> Int {
        return 2 * index + 2
    }
}
