func solve(n: Int64, edges: Array<Array<Int64>>): Int64 {
    let adj = array(n, fun _ => array(0, fun _ => (0, 0)))
    let rev_adj = array(n, fun _ => array(0, fun _ => (0, 0)))

    for e in edges {
        let u = e[0]
        let v = e[1]
        let w = e[2]
        adj[u].append((v, w))
        rev_adj[v].append((u, w))
    }

    let dist = array(n, fun _ => array(2, fun _ => none<int64>))
    let mut heap = min_heap<State>()

    heap.push(State { node = 0, cost = 0, used_switch = false })
    dist[0][0] = some(0)

    while let Some(state) = heap.pop() {
        let u = state.node
        let current_cost = state.cost
        let used = state.used_switch

        if u == n - 1 {
            return current_cost
        }

        if let Some(d) = dist[u][used] {
            if current_cost > d {
                continue
            }
        }

        for (v, w) in adj[u] {
            let new_cost = current_cost + w
            if dist[v][used] == none || new_cost < dist[v][used].unwrap() {
                dist[v][used] = some(new_cost)
                heap.push(State { node = v, cost = new_cost, used_switch = used })
            }
        }

        if !used {
            for (v, w) in rev_adj[u] {
                let new_cost = current_cost + 2 * w
                if dist[v][true] == none || new_cost < dist[v][true].unwrap() {
                    dist[v][true] = some(new_cost)
                    heap.push(State { node = v, cost = new_cost, used_switch = true })
                }
            }
        }
    }

    let res0 = dist[n - 1][0]
    let res1 = dist[n - 1][1]

    if res0 == none && res1 == none {
        return -1
    } else if res0 == none {
        return res1.unwrap()
    } else if res1 == none {
        return res0.unwrap()
    } else {
        return min(res0.unwrap(), res1.unwrap())
    }
