    int64 cost;
    bool used_switch;
}

bool operator < (const State& a, const State& b) {
    return a.cost > b.cost;
}

func solve(n: Int64, edges: Array<Array<Int64>>): Int64 {
    int64 num_nodes = n;
    vector<vector<Edge>> graph(num_nodes);
    vector<vector<Edge>> reverse_graph(num_nodes);

    for (int64 i = 0; i < edges.size(); ++i) {
        auto edge = edges[i];
        int64 u = edge[0];
        int64 v = edge[1];
        int64 w = edge[2];
        graph[u].push_back(Edge{v, w, i});
        reverse_graph[v].push_back(Edge{u, w, i});
    }

    vector<vector<int64>> dist(num_nodes, vector<int64>(2, -1));
    priority_queue<State> pq;

    pq.push(State{0, 0, false});
    dist[0][0] = 0;

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();

        if (current.node == num_nodes - 1) {
            return current.cost;
        }

        if (dist[current.node][current.used_switch] != -1 && dist[current.node][current.used_switch] < current.cost) {
            continue;
        }

        for (const auto& edge : graph[current.node]) {
            int64 new_cost = current.cost + edge.weight;
            if (dist[edge.to][current.used_switch] == -1 || new_cost < dist[edge.to][current.used_switch]) {
