                pq.push(State{edge.to, new_cost, current.used_switch});
            }
        }

        if (!current.used_switch) {
            for (const auto& edge : reverse_graph[current.node]) {
                int64 new_cost = current.cost + 2 * edge.weight;
                if (dist[edge.to][true] == -1 || new_cost < dist[edge.to][true]) {
                    dist[edge.to][true] = new_cost;
                    pq.push(State{edge.to, new_cost, true});
                }
            }
        }
    }

