import Foundation

func solve(n: Int64, edges: Array<Array<Int64>>) -> Int64 {
    let n = Int(n)
    var adj = [[(v: Int, w: Int)]](repeating: [], count: n)
    var reversedAdj = [[(v: Int, w: Int)]](repeating: [], count: n)

    for edge in edges {
        let u = Int(edge[0])
        let v = Int(edge[1])
        let w = Int(edge[2])
        adj[u].append((v: v, w: w))
        reversedAdj[v].append((v: u, w: w))
    }

    // Priority queue: (cost, node, usedSwitch)
    var heap = Heap<(cost: Int, node: Int, usedSwitch: Bool)> { $0.cost < $1.cost }
    heap.insert((cost: 0, node: 0, usedSwitch: false))

    var dist = [[Int]](repeating: [Int](repeating: Int.max, count: 2), count: n)
    dist[0][0] = 0

    while !heap.isEmpty {
        let current = heap.remove()!
        let (cost, u, usedSwitch) = (current.cost, current.node, current.usedSwitch)

        if u == n - 1 {
            return Int64(cost)
        }

        if cost > dist[u][usedSwitch ? 1 : 0] {
            continue
        }

        // Normal edges
        for edge in adj[u] {
            let (v, w) = (edge.v, edge.w)
            let newCost = cost + w
            if newCost < dist[v][usedSwitch ? 1 : 0] {
                dist[v][usedSwitch ? 1 : 0] = newCost
                heap.insert((cost: newCost, node: v, usedSwitch: usedSwitch))
            }
        }

        // If not used switch yet, try reversing an incoming edge
        if !usedSwitch {
            for edge in reversedAdj[u] {
                let (v, w) = (edge.v, edge.w)
                let newCost = cost + 2 * w
                if newCost < dist[v][1] {
                    dist[v][1] = newCost
                    heap.insert((cost: newCost, node: v, usedSwitch: true))
                }
            }
        }
    }

    let res = min(dist[n-1][0], dist[n-1][1])
    return res == Int.max ? -1 : Int64(res)
}

// Priority Queue implementation
struct Heap<T> {
    private var elements: [T]
    private let priorityFunction: (T, T) -> Bool

    var isEmpty: Bool {
        return elements.isEmpty
    }

    init(sort: @escaping (T, T) -> Bool) {
        self.elements = []
        self.priorityFunction = sort
    }

    mutating func insert(_ value: T) {
        elements.append(value)
        siftUp(from: elements.count - 1)
    }

    mutating func remove() -> T? {
        if elements.isEmpty {
            return nil
        }
        if elements.count == 1 {
            return elements.removeLast()
        }
        elements.swapAt(0, elements.count - 1)
        let value = elements.removeLast()
        siftDown(from: 0)
        return value
    }

    private mutating func siftUp(from index: Int) {
        var child = index
        var parent = parentIndex(of: child)
        while child > 0 && priorityFunction(elements[child], elements[parent]) {
            elements.swapAt(child, parent)
            child = parent
            parent = parentIndex(of: child)
        }
    }

    private mutating func siftDown(from index: Int) {
        var parent = index
        while true {
            let left = leftChildIndex(of: parent)
            let right = rightChildIndex(of: parent)
            var candidate = parent
            if left < elements.count && priorityFunction(elements[left], elements[candidate]) {
                candidate = left
            }
            if right < elements.count && priorityFunction(elements[right], elements[candidate]) {
                candidate = right
            }
            if candidate == parent {
                return
            }
            elements.swapAt(parent, candidate)
            parent = candidate
        }
    }

    private func parentIndex(of index: Int) -> Int {
        return (index - 1) / 2
    }

    private func leftChildIndex(of index: Int) -> Int {
        return 2 * index + 1
    }

    private func rightChildIndex(of index: Int) -> Int {
        return 2 * index + 2
    }
}
