                let v = edge.first;
                let w = edge.second;
                if dist[v][1] == -1 || dist[v][1] > current_dist + 2 * w {
                    dist[v][1] = current_dist + 2 * w;
                    heap.push(pair(dist[v][1], pair(v, 1)));
                }
            }
        }
    }

    let res = min(dist[n - 1][0], dist[n - 1][1]);
    if res == -1 {
        return max(dist[n - 1][0], dist[n - 1][1]);
    }
    return res;
}
